mapper.select:
SELECT s.id, t.value as time_zone FROM site s INNER JOIN time_zone t on t.id = s.id_time_zone WHERE s.solar_edge_id is NOT NULL AND s.solar_edge_api_key is NOT NULL AND s.solar_edge_auto_backfill = 1 AND s.is_delete = 0 AND s.status = 1
AND s.run_on_server IN
#{item}
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE device
SET is_delete = 0
WHERE id = #{id}
